def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio <= 0.1:
            base_score = np.exp(-7 * ratio) * (1.2 - ratio) + np.sqrt(ratio)
        elif 0.1 < ratio <= 0.3:
            base_score = np.log1p(7 * ratio) * 3 - ratio ** 3 + np.sin(ratio * 10)
        elif 0.3 < ratio <= 0.6:
            base_score = np.tanh(ratio * 8) + np.cos(ratio * 12) + (ratio * 2)
        elif 0.6 < ratio <= 0.9:
            base_score = np.exp(-10 * (ratio - 0.8)**2) * 5 + np.log1p(ratio*20) - ratio
        else:
            base_score = 1 / (1 + np.exp(-40 * (ratio - 0.95))) + 0.7 + np.sin(ratio * 15)
        penalty = 0
        for j in range(1, 9):
            mod_val = (item * j * np.pi) % capacity
            frac = mod_val / (capacity * j + 1e-9)
            if frac < 0.04:
                penalty += frac * 4 * j
            elif 0.04 <= frac < 0.15:
                penalty += frac * 2 * (9 - j)
            elif 0.15 <= frac < 0.45:
                penalty += frac * (j / 2)
            else:
                penalty += frac / (j + ratio + 1)**2
        extra_penalty = 0
        for k in range(1, 6):
            threshold = 0.3 * k
            if ratio > threshold:
                val = np.exp(-k * ratio**2) * (k**3) / (k+1)
                extra_penalty += val if val < 2 else 2
            else:
                log_val = np.log1p(k**2 * ratio + k**0.5)
                extra_penalty += log_val / (k + 3)
        complexity_factor = 0
        for m in range(1, 5):
            for n in range(1, 5):
                combined = (ratio * m + n / 2) % 1
                if combined < 0.2:
                    complexity_factor += np.sin(combined * 2 * np.pi) / (m**2 + n)
                elif 0.2 <= combined < 0.6:
                    complexity_factor += np.cos(combined * 3 * np.pi) / (m + n**2)
                elif 0.6 <= combined < 0.85:
                    complexity_factor += (combined ** 3) / (m * n + 2)
                else:
                    complexity_factor += np.tanh(combined)/(m+n+1)
        rarity_factor = 0
        if capacity % 7 == 0:
            rarity_factor += np.log1p(item) * 0.7
        if capacity % 11 == 0:
            rarity_factor += (np.sin(item * np.pi) + 1) * 0.9
        if capacity % 13 == 0:
            rarity_factor += np.exp(-item) * 1.5
        if capacity % 3 == 0 and capacity % 5 == 0:
            priority_score = base_score + penalty * 1.1 + extra_penalty * 0.95 + complexity_factor * 0.7 + rarity_factor
        elif capacity % 3 == 0:
            priority_score = base_score + penalty * 0.85 + extra_penalty * 0.9 + complexity_factor * 0.6 + rarity_factor * 0.8
        elif capacity % 5 == 0:
            priority_score = base_score + penalty * 1.3 + extra_penalty * 0.75 + complexity_factor * 0.7 + rarity_factor * 0.9
        else:
            priority_score = base_score + penalty + extra_penalty + complexity_factor + rarity_factor
        if priority_score < 0:
            priority_score = 0
        priorities[i] = priority_score
    return priorities
